def sanitize_grok_api_key(api_key: str) -> str:
    """清洗 Grok/x.ai API Key，避免请求头里出现换行、空格、引号或误粘贴的 Bearer 前缀。"""
    key = api_key or ""
    key = key.replace("\ufeff", "").replace("\u200b", "").replace("\u200c", "").replace("\u200d", "")
    key = key.strip().strip('\'"')
    if key.lower().startswith("bearer "):
        key = key[7:]
    # requests 的 Header value 不能包含换行、回车、制表符或前后空格；这里直接删除所有空白字符。
    key = re.sub(r"\s+", "", key)
    return key


