def sanitize_doubao_endpoint_id(endpoint_id: str) -> str:
    """清洗并提取火山方舟推理接入点 ID。

    允许用户从代码片段、日志或说明文字中粘贴，例如：
    model="ep-20260531xxxx"，会自动提取 ep-...。
    但不会接受中文占位符，例如 ep-请填写推理接入点ID。
    """
    ep = str(endpoint_id or "")
    ep = ep.replace("\ufeff", "").replace("\u200b", "").replace("\u200c", "").replace("\u200d", "")
    ep = ep.strip().strip('"\'')
    # 从粘贴的代码 / 日志 / URL 参数中提取第一个看起来像 Endpoint ID 的片段。
    m = re.search(r"(?<![A-Za-z0-9_-])(ep-[A-Za-z0-9][A-Za-z0-9_-]{5,127})(?![A-Za-z0-9_-])", ep)
    if m:
        return m.group(1)
    ep = re.sub(r"\s+", "", ep)
    return ep


def is_valid_doubao_endpoint_id(endpoint_id: str) -> bool:
    ep = sanitize_doubao_endpoint_id(endpoint_id)
    # Endpoint ID 只允许 ASCII 字母、数字、下划线、连字符；拒绝中文占位符。
    return bool(re.fullmatch(r"ep-[A-Za-z0-9][A-Za-z0-9_-]{5,127}", ep or ""))


