def _deep_merge_dict(base: dict, override: dict) -> dict:
    """递归合并后处理参数；只覆盖用户写到的字段，未写字段保持默认稳定值。"""
    result = dict(base or {})
    for key, value in (override or {}).items():
        if isinstance(value, dict) and isinstance(result.get(key), dict):
            result[key] = _deep_merge_dict(result.get(key, {}), value)
        else:
            result[key] = value
    return result


def _parse_scalar_config_value(value: str):
    text = str(value or "").strip().strip(",")
    if not text:
        return ""
    if (text.startswith('"') and text.endswith('"')) or (text.startswith("'") and text.endswith("'")):
        return text[1:-1]
    low = text.lower()
    if low in {"true", "yes", "on"}:
        return True
    if low in {"false", "no", "off"}:
        return False
    if low in {"none", "null"}:
        return None
    m = re.match(r"^(-?\d+(?:\.\d+)?)\s*%\s*(?:of\s*)?[WHwh]?\s*$", text)
    if m:
        try:
            return float(m.group(1)) / 100.0
        except Exception:
            return text
    try:
        if re.match(r"^-?\d+$", text):
            return int(text)
        if re.match(r"^-?\d+\.\d+$", text):
            return float(text)
    except Exception:
        pass
    return text


def _normalize_postprocess_config_value(value):
    """允许用户粘贴 4.5%H / 6%W / 80%W 这类写法，内部统一转为 0.045 / 0.06 / 0.80。"""
    if isinstance(value, dict):
        out = {}
        for key, sub in value.items():
            norm_key = str(key)
            # 兼容用户自然写法：border_radius / offset_y 转为程序实际字段。

            if norm_key == "border_radius":
                norm_key = "border_radius_ratio_w"
            elif norm_key == "offset_y":
                norm_key = "offset_y_ratio_h"
            out[norm_key] = _normalize_postprocess_config_value(sub)
        return out

    if isinstance(value, list):
        return [_normalize_postprocess_config_value(v) for v in value]
    if isinstance(value, str):
        return _parse_scalar_config_value(value)
    return value


def _extract_first_json_object(text: str) -> str:
    raw = str(text or "").strip()
    raw = re.sub(r"^```(?:json)?\s*", "", raw, flags=re.I).strip()
    raw = re.sub(r"\s*```$", "", raw).strip()
    if raw.startswith("{") and raw.endswith("}"):
        return raw
    start = raw.find("{")
    end = raw.rfind("}")
    if start >= 0 and end > start:
        return raw[start:end + 1]
    return ""


def parse_postprocess_requirements_text(text: str) -> dict:
    """解析提示词中心里的后处理参数。
    支持两种方式：
    1) JSON 对象；
    2) 简写覆盖行，如：cover_layout.brand_y = 0.045 或 ending_card_style.shadow.opacity = 0.02。
    无法解析的自然语言会被保留在配置文件里，但不会改变确定性后处理，避免凭空猜测。
    """
    raw = str(text or "").strip()
    if not raw:
        return {}
    json_part = _extract_first_json_object(raw)
    if json_part:
        try:
            data = json.loads(json_part)
            return _normalize_postprocess_config_value(data if isinstance(data, dict) else {})
        except Exception:
            pass

    data = {}
    for line in raw.splitlines():
        line = line.strip()
        if not line or line.startswith(("#", "//")):
            continue
        m = re.match(r"^([A-Za-z0-9_\.]+)\s*(?:=|:)\s*(.+?)\s*$", line)
        if not m:
            continue
        path, value = m.group(1), _normalize_postprocess_config_value(_parse_scalar_config_value(m.group(2)))
        cur = data
        parts = [p for p in path.split(".") if p]
        for part in parts[:-1]:
            cur = cur.setdefault(part, {})
        if parts:
            cur[parts[-1]] = value
    return data



def _compact_json_for_prompt(value, max_chars: int = 9000) -> str:
    """给大模型看的紧凑 JSON；超过长度时保守截断，避免 UI 规范化调用过重。"""
    try:
        text = json.dumps(value, ensure_ascii=False, indent=2)
    except Exception:
        text = str(value or "")
    if len(text) > max_chars:
        return text[:max_chars].rstrip() + "\n...（后续字段已截断；未提到的字段保持当前值）"
    return text



def _strip_prompt_text_from_llm(raw: str) -> str:
    """清理大模型返回的提示词文本，去掉代码围栏和解释性包裹。"""
    s = str(raw or "").strip()
    if not s:
        return ""
    s = re.sub(r"^```(?:text|markdown|md|prompt)?\s*", "", s, flags=re.I).strip()
    s = re.sub(r"\s*```\s*$", "", s).strip()
    # 部分模型会加“以下是优化后的提示词：”，只去掉开头一行，不碰正文结构。
    s = re.sub(r"^(?:以下是|这是|优化后的|整合后的).{0,24}(?:提示词|模板)[:：]\s*\n", "", s).strip()
    return s


def build_prompt_template_normalization_prompt(natural_request: str, current_template: str, template_key: str, style_key: str) -> str:
    """把用户对脚本/润色提示词的模糊要求转换为可直接替换的完整提示词模板。"""
    template_key = str(template_key or "").strip()
